#!/usr/bin/env node
// Reads ../config/branding.yaml and emits ../src/lib/branding.generated.ts.
//
// Doctrine refs: Rule 80 (white-label conformance), Rule 56 (automation
// over process — generation runs as `npm prebuild` so the build always
// reflects the current branding.yaml).
//
// Runs from the frontend/ working directory. The generated file is
// committed (gitignored: false) so IDE TypeScript checking works without
// running the generator first; CI re-runs the generator and asserts the
// committed file matches the freshly-generated one.

import { readFileSync, writeFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { parse as parseYaml } from 'yaml';

const here = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(here, '..', '..');
const corePath = resolve(repoRoot, 'config', 'branding.yaml');
const outPath = resolve(here, '..', 'src', 'lib', 'branding.generated.ts');

const yamlText = readFileSync(corePath, 'utf-8');
const branding = parseYaml(yamlText);

// Engagement-overlay path is engagements/<id>/config/branding.yaml; resolved
// at runtime by the engagement-fork's bootstrap (Phase 1 — engagement-fork-
// bootstrap.md). The generator pulls Core defaults only — overlays are
// applied by the engagement fork's own re-run of this generator after
// editing engagements/<id>/config/branding.yaml.

const stamp = new Date().toISOString();
const ts = `// AUTO-GENERATED by frontend/scripts/gen-branding.mjs at ${stamp}.
// SOURCE: config/branding.yaml (engagement-overridable per Rule 82).
// EDIT: config/branding.yaml + run \`npm run gen:branding\` (or \`npm run build\`).
//
// Doctrine refs: Rule 80 (white-label conformance), Rule 82 (engagement overlay).
// Charter ref: §6 (white-label readiness).

export const branding = ${JSON.stringify(branding, null, 2)} as const;

export type Branding = typeof branding;

export const productName = branding.product.name;
export const productTagline = branding.product.tagline;
export const productDescription = branding.product.description;
export const vendorName = branding.vendor.name;
export const supportEmail = branding.vendor.support_email;
export const primaryColor = branding.theme.primary_color;
export const accentColor = branding.theme.accent_color;
export const backgroundColor = branding.theme.background_color;
export const logoPath = branding.theme.logo_path;
export const faviconPath = branding.theme.favicon_path;
export const footerHTML = branding.footer.html.replace(/\\{\\{year\\}\\}/g, String(new Date().getFullYear()));
export const showPoweredBy = branding.footer.show_powered_by;
`;

writeFileSync(outPath, ts);
console.log(`gen-branding: wrote ${outPath} (${ts.length} bytes)`);
